import React, { useCallback, useEffect, useMemo, useState } from 'react';
import { LinErpListFilterBar, Select, dispatchAppToast } from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { analyticsService } from '../../../services/analytics/analyticsService';
import { formatNumber, formatVnd } from '../../../utils/formatters';
import { monthStartEnd } from '../../../utils/exportExcel';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import reportStyles from '../../../styles/erpReportPage.module.css';
import type { WarehouseDto, StockBalanceRow } from '../../../services/analytics/models';
import { AnalyticsReportShell, ReportTableWrap } from '../../../components/report';

const TEST_ID = 'erp-bao-cao-nxt';
const PAGE_ID = 'baocao-nxt';

const BaoCaoNxtPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { fromDate: iF, toDate: iT } = monthStartEnd();
  const [fromDate, setFromDate] = useState(iF);
  const [toDate, setToDate] = useState(iT);
  const [warehouseId, setWarehouseId] = useState('');
  const [warehouses, setWarehouses] = useState<WarehouseDto[]>([]);
  const [rows, setRows] = useState<StockBalanceRow[]>([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      analyticsService
        .getWarehouses()
        .then(d => {
          if (!cancelled) setWarehouses(d);
        })
        .catch(() => {});
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, []);

  const handleLoad = useCallback(() => {
    setLoading(true);
    analyticsService
      .getStockBalance({ fromDate, toDate, warehouseId: warehouseId || undefined, asOfDate: toDate })
      .then(setRows)
      .catch(err =>
        dispatchAppToast(dispatch, {
          message: getApiErrorMessage(err, 'Lỗi'),
          type: 'error',
        }),
      )
      .finally(() => setLoading(false));
  }, [fromDate, toDate, warehouseId, dispatch]);

  const listFilters = useMemo(
    () => (
      <LinErpListFilterBar
        testIdPrefix={TEST_ID}
        fromDate={fromDate}
        toDate={toDate}
        onDateChange={(from, to) => {
          setFromDate(from ?? '');
          setToDate(to ?? '');
        }}
        dateLabel="Thời gian"
        expandDateRangeAriaLabel="Thêm ngày kết thúc"
        onSearch={handleLoad}
        searchAriaLabel="Xem"
        loading={loading}
        leading={(
          <div data-testid={`${TEST_ID}-field-warehouse`}>
            <Select
              label="Kho"
              value={warehouseId}
              onChange={e => setWarehouseId(e.target.value)}
              options={[
                { value: '', label: 'Tất cả kho' },
                ...warehouses.map(w => ({ value: String(w.id), label: w.name })),
              ]}
              size="small"
            />
          </div>
        )}
      />
    ),
    [fromDate, toDate, warehouseId, warehouses, handleLoad, loading],
  );

  return (
    <AnalyticsReportShell
      testId={TEST_ID}
      pageId={PAGE_ID}
      title="Nhập xuất tồn"
      titleIconClass="fas fa-boxes"
      loading={loading}
      hasData={rows.length > 0}
      filters={listFilters}
      onLoad={handleLoad}
      exportPath="/reports/warehouse/nxt/export-excel"
      exportParams={{ fromDate, toDate, warehouseId: warehouseId || undefined }}
      exportFilename={`NXT-${fromDate}.xlsx`}
    >
      <ReportTableWrap testId={`${TEST_ID}-grid`}>
        <thead>
          <tr>
            <th>Mã</th>
            <th>Tên</th>
            <th>Kho</th>
            <th className={reportStyles.colRight}>Tồn đầu</th>
            <th className={reportStyles.colRight}>Nhập</th>
            <th className={reportStyles.colRight}>Xuất</th>
            <th className={reportStyles.colRight}>Tồn cuối</th>
            <th className={reportStyles.colRight}>Giá trị</th>
          </tr>
        </thead>
        <tbody>
          {rows.map((r, i) => (
            <tr key={i}>
              <td>{r.materialCode}</td>
              <td>{r.materialName}</td>
              <td>{r.warehouseName}</td>
              <td className={reportStyles.colRight}>{formatNumber(r.openingQuantity)}</td>
              <td className={reportStyles.colRight}>{formatNumber(r.receivedQuantity)}</td>
              <td className={reportStyles.colRight}>{formatNumber(r.issuedQuantity)}</td>
              <td className={reportStyles.colRight}>{formatNumber(r.closingQuantity)}</td>
              <td className={reportStyles.colRight}>{formatVnd(r.closingAmount)}</td>
            </tr>
          ))}
        </tbody>
      </ReportTableWrap>
    </AnalyticsReportShell>
  );
};

export default BaoCaoNxtPage;
